// Get all watched locations and all nearest stations
const watches = $('Fetch All Watched Favorite Locations').all().map(item => item.json);
const stations = $input.all().map(item => item.json);

// Match each watch with its corresponding station (by index)
const results = watches.map((watch, index) => {
  const station = stations[index] || {};

  // Parse thresholds (handle string values)
  const aqiThreshold = parseInt(watch.aqi_threshold) || 100;
  const pm25Threshold = parseFloat(watch.pm25_threshold) || 35;
  const lastAqi = station.last_aqi ? parseInt(station.last_aqi) : 0;
  const lastPm25 = station.last_pm25 ? parseFloat(station.last_pm25) : 0;

  const breach = (lastAqi >= aqiThreshold) || (lastPm25 >= pm25Threshold);

  return {
    json: {
      ...watch,
      station_name: station.station_name || 'Unknown',
      last_aqi: lastAqi,
      last_pm25: lastPm25,
      wind_speed_kmh: station.wind_speed_kmh || null,
      breach: breach
    }
  };
});

return results;

