const items = $input.all();

// Extract unique entries, maintaining their structural item data
const userMap = {};
for (const item of items) {
  const userId = item.json.user_id;
  if (userId && !userMap[userId]) {
    userMap[userId] = item.json;
  }
}

// Pass along the full breach details uniquely matching the user_id
return Object.values(userMap).map(item => ({
  json: {
    ...item // Spreads the full matching location, lat, lon, and breach data down the execution line
  }
}));

const items = $input.all();

// Fetch the full historical record batch array from the initial evaluation step
const breachRecords = $('Evaluate Threshold Breach').all().map(item => item.json);

function escape(str) {
  if (str === null || str === undefined) return 'NULL';
  return "'" + String(str).replace(/'/g, "''") + "'";
}

const results = items.map(item => {
  const pushResult = item.json;

  // Find the exact historical payload block matching the current record context
  // Fallback to the first item only if a match is not found
  const matchedBreach = breachRecords.find(b => b.user_id === pushResult.user_id) || breachRecords[0];

  const triggeredBy = pushResult.onesignal_player_id ? 'app_push' : 'telegram_push';

  const sql = `
INSERT INTO haze_alert_logs (
  user_id, triggered_by, aqi_at_trigger, safety_status,
  label, station_name, pm25_at_trigger, pm25_threshold, aqi_threshold
) VALUES (
  ${escape(matchedBreach.user_id)},
  '${triggeredBy}',
  ${matchedBreach.last_aqi ?? 'NULL'},
  'Incoming Plume Warning',
  ${escape(matchedBreach.label)},
  ${escape(matchedBreach.station_name)},
  ${matchedBreach.last_pm25 ?? 'NULL'},
  ${matchedBreach.pm25_threshold ?? 'NULL'},
  ${matchedBreach.aqi_threshold ?? 'NULL'}
)
`;

  return { json: { sql } };
});

return results;

